1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a 2x2 block unchanged (still-life)", () => {
15	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	    expect(new Set(result.map(c => c.join(",")))).toEqual(
17	      new Set([[0, 0], [1, 0], [0, 1], [1, 1]].map(c => c.join(",")))
18	    );
19	  });
20	  it("should rotate a vertical blinker into a horizontal blinker", () => {
21	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
22	    expect(new Set(result.map(c => c.join(",")))).toEqual(
23	      new Set([[-1, 1], [0, 1], [1, 1]].map(c => c.join(",")))
24	    );
25	  });
26	  it("should kill the center of a filled 3x3 and produce corners-only pattern (overpopulation)", () => {
27	    const result = nextGeneration([
28	      [0, 0], [1, 0], [2, 0],
29	      [0, 1], [1, 1], [2, 1],
30	      [0, 2], [1, 2], [2, 2],
31	    ]);
32	    expect(new Set(result.map(c => c.join(",")))).toEqual(
33	      new Set([
34	        [0, 0], [2, 0], [0, 2], [2, 2],
35	        [-1, 1], [1, -1], [3, 1], [1, 3],
36	      ].map(c => c.join(",")))
37	    );
38	  });
39	  it("should bring a dead cell with exactly 3 live neighbors to life (reproduction)", () => {
40	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
41	    expect(new Set(result.map(c => c.join(",")))).toEqual(
42	      new Set([[0, 0], [1, 0], [0, 1], [1, 1]].map(c => c.join(",")))
43	    );
44	  });
45	  it.todo("should handle negative coordinates correctly");
46	});
47

1	type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	const survives = (isAlive: boolean, liveNeighbors: number): boolean =>
15	  liveNeighbors === 3 || (isAlive && liveNeighbors === 2);
16	
17	export function nextGeneration(liveCells: Cell[]): Cell[] {
18	  const liveKeys = new Set(liveCells.map(cellKey));
19	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
20	
21	  for (const cell of liveCells) {
22	    for (const neighbor of neighborsOf(cell)) {
23	      const key = cellKey(neighbor);
24	      const previousCount = neighborCounts.get(key)?.count ?? 0;
25	      neighborCounts.set(key, { cell: neighbor, count: previousCount + 1 });
26	    }
27	  }
28	
29	  const survivors: Cell[] = [];
30	  for (const [key, { cell, count }] of neighborCounts) {
31	    if (survives(liveKeys.has(key), count)) {
32	      survivors.push(cell);
33	    }
34	  }
35	
36	  return survivors;
37	}
